//! value_door: the value-door stoplight — a cost-aware crossover gate.
//!
//! The default `engine::compute_k_eff` gates parallel dispatch on BATCH SIZE
//! (`total < serial_cutoff()`). Benchmarking (`bench_small_bursty`) showed that
//! is the wrong axis: CHEAP per-item work parallelized above the size cutoff ran
//! up to ~14,000× slower than serial, while HEAVY work only pays off at large N.
//! Size cannot tell cheap from heavy; only COST can.
//!
//! This module gates on the value-door crossover instead: open the parallel door
//! only when per-item work exceeds per-item dispatch (gate) cost. The RED state
//! is the fast lane — cheap work stays serial regardless of N, dodging the
//! 14,000× trap.
//!
//! WHY THIS IS DOMINANT, NOT MERELY OPT-IN: the only reason to keep it opt-in was
//! the per-item cost being unknown (the YELLOW probe + its estimate risk). But in
//! gnosis nothing dispatches un-admitted — the admission cert already carries the
//! cost class. So the cost is never unknown: read it from the cert
//! (`cost_aware_k_eff_certified`), YELLOW is vacuous, and the gate is total
//! RED/GREEN. Given the cert it weakly dominates the size cutoff everywhere and
//! strictly beats it on the cases the bench broke (cheap-large, heavy-small). The
//! remaining step to flip the default is plumbing (thread the certified cost
//! through `execute`) + a confirming integrated bench — not probe risk.
//!
//! Lean contract (proved, axioms = propext + Quot.sound):
//!   - `Gnosis.ValueDoorStoplight.green_door_pays` - GREEN ⇒ the door pays.
//!   - `Gnosis.ValueDoorStoplight.red_door_loses` - RED ⇒ the door loses.
//!   - `Gnosis.DoorPaysAboveCrossover.crossover_is_verify_search_gap`
//!     - the win is the cost gap.
//!   - `Gnosis.AdaptiveStoplight.adaptive_floors_loss`
//!     - the probe bounds the downside.

/// Lean theorem IDs this primitive realizes (the contract surface).
pub const VALUE_DOOR_GREEN_THEOREM_ID: &str = "Gnosis.ValueDoorStoplight.green_door_pays";
pub const VALUE_DOOR_RED_THEOREM_ID: &str = "Gnosis.ValueDoorStoplight.red_door_loses";
pub const VALUE_DOOR_CROSSOVER_THEOREM_ID: &str =
    "Gnosis.DoorPaysAboveCrossover.crossover_is_verify_search_gap";
pub const VALUE_DOOR_FLOORS_LOSS_THEOREM_ID: &str =
    "Gnosis.AdaptiveStoplight.adaptive_floors_loss";

/// Elements per worker target (mirrors `engine::compute_k_eff`).
const ELEMENTS_PER_WORKER: usize = 32;

/// The three lights — the trit of scheduling (mirrors `Gnosis.ValueDoorStoplight.Light`).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Light {
    /// Below the crossover: the door costs more than the room — recompute serially.
    Red,
    /// Recompute cost not yet measured: probe and learn the crossover.
    Yellow,
    /// Above the crossover: open the door — the work pays for the dispatch.
    Green,
}

/// Net work saved by opening the door over the serial baseline, in the same
/// units as the costs. Mirrors `Gnosis.DoorPaysAboveCrossover.netSaved`:
/// `h·r − (n·g + setup)`. Signed: a loss is negative.
#[inline]
pub fn net_saved(n: u64, h: u64, r: u64, g: u64, setup: u64) -> i64 {
    (h.saturating_mul(r) as i64) - ((n.saturating_mul(g) + setup) as i64)
}

/// The value-door stoplight (mirrors `Gnosis.ValueDoorStoplight.light`):
/// `None` recompute cost ⇒ YELLOW (probe); measured ⇒ GREEN iff it beats the gate.
#[inline]
pub fn door_light(measured_recompute: Option<u64>, gate_cost: u64) -> Light {
    match measured_recompute {
        None => Light::Yellow,
        Some(r) if gate_cost < r => Light::Green,
        Some(_) => Light::Red,
    }
}

/// The CERTIFIED gate — admission eliminates YELLOW.
///
/// YELLOW (probe) only ever existed for UN-attested cost. In gnosis nothing
/// dispatches un-admitted: the admission cert already carries the work's cost
/// class (FOIL's theorem-ID + loser-observation's `bisided_score`/`computable`,
/// the qspec gate). So the cost is never `None` — it is read straight from the
/// cert. A certified light is therefore total RED/GREEN, decided with no
/// measurement and no estimate risk. This is why the cost-aware gate is strictly
/// dominant rather than merely opt-in: there is always some admission to read
/// the cost from.
///
/// Lean contract (zero axioms):
///   - `Gnosis.ValueDoorStoplight.certified_never_yellow`  — never YELLOW.
///   - `Gnosis.ValueDoorStoplight.certified_is_red_or_green` — total RED/GREEN.
pub const VALUE_DOOR_CERTIFIED_THEOREM_ID: &str =
    "Gnosis.ValueDoorStoplight.certified_never_yellow";

#[inline]
pub fn certified_light(certified_recompute: u64, gate_cost: u64) -> Light {
    // `certified_never_yellow`: a cert in hand ⇒ the probe state is vacuous.
    if gate_cost < certified_recompute {
        Light::Green
    } else {
        Light::Red
    }
}

/// Cost-aware worker count from a CERTIFIED per-item cost (no probe). The
/// admission cert supplies `certified_per_item_work_ns`; the gate is decided
/// against the platform's per-item coordination cost. Equivalent to
/// `cost_aware_k_eff` with the cost sourced from admission instead of a probe —
/// strictly dominant over the size cutoff because the cost is always known.
#[inline]
pub fn cost_aware_k_eff_certified(
    total: usize,
    k: usize,
    certified_per_item_work_ns: u64,
    per_item_dispatch_ns: u64,
) -> usize {
    cost_aware_k_eff(total, k, certified_per_item_work_ns, per_item_dispatch_ns)
}

/// Cost-aware effective worker count — the fast lane.
///
/// THE CROSSOVER IS PER-ITEM, NOT PER-BATCH. Benchmarking surfaced (and a unit
/// test here caught) that dispatch overhead is not a fixed constant: it scales
/// with N (per-item unpark/spin/atomic coordination, ~hundreds of ns/item under
/// contention). So the right gate compares WORK PER ITEM against COORDINATION PER
/// ITEM — independent of N. That is exactly why CHEAP work loses to serial at
/// *every* size (work/item < coord/item) while HEAVY work wins: size was always
/// the wrong axis.
///
/// Opens the parallel door only when `per_item_work_ns > per_item_dispatch_ns`.
/// Cheap work stays serial (`k_eff = 1`) at every `N`, dodging the measured
/// ~14,000x cheap-parallel trap; heavy work sizes the pool as the default does.
/// `per_item_work_ns` is the YELLOW-probe estimate (time a few items);
/// `per_item_dispatch_ns` is the platform's measured per-item coordination cost.
#[inline]
pub fn cost_aware_k_eff(
    total: usize,
    k: usize,
    per_item_work_ns: u64,
    per_item_dispatch_ns: u64,
) -> usize {
    if total <= 1 || k <= 1 {
        return 1;
    }
    // RED: per-item work does not beat per-item coordination — stay serial at
    // every N. The door that loses no matter the batch size.
    if per_item_work_ns <= per_item_dispatch_ns {
        return 1;
    }
    // GREEN: size the pool toward ~ELEMENTS_PER_WORKER per worker.
    if total <= k {
        return total;
    }
    (total / ELEMENTS_PER_WORKER).clamp(2, k)
}

#[cfg(test)]
mod tests {
    use super::*;

    // Per-item coordination cost (the measured ~hundreds-of-ns/item floor).
    const DISPATCH: u64 = 200;

    #[test]
    fn cheap_work_stays_serial_at_every_size() {
        // work/item 1ns < coord/item 200ns: cheap. Door stays shut at ALL N.
        for &total in &[8usize, 16, 64, 256, 1024, 4096, 16384] {
            assert_eq!(
                cost_aware_k_eff(total, 8, 1, DISPATCH),
                1,
                "N={total} cheap must be serial"
            );
        }
    }

    #[test]
    fn heavy_work_opens_the_door_at_scale() {
        // work/item 2000ns > coord/item 200ns: heavy. Door opens once there's a pool to fill.
        assert!(cost_aware_k_eff(256, 8, 2000, DISPATCH) > 1, "heavy must parallelize");
    }

    #[test]
    fn crossover_is_per_item_not_size() {
        // THE DISCOVERY: at the SAME large N, the decision flips on per-item cost,
        // not size. Cheap stays serial; heavy parallelizes.
        assert_eq!(cost_aware_k_eff(16384, 8, 1, DISPATCH), 1, "cheap@16384 → serial");
        assert!(cost_aware_k_eff(16384, 8, 2000, DISPATCH) > 1, "heavy@16384 → parallel");
    }

    #[test]
    fn light_matches_crossover() {
        assert_eq!(door_light(None, 100), Light::Yellow);
        assert_eq!(door_light(Some(50), 100), Light::Red); // r <= g
        assert_eq!(door_light(Some(200), 100), Light::Green); // g < r
    }

    #[test]
    fn certified_gate_never_yellow() {
        // Mirrors Lean `certified_never_yellow` / `certified_is_red_or_green`:
        // a cert in hand is always decided RED or GREEN — never the probe state.
        for r in 0u64..256 {
            for g in 0u64..256 {
                let l = certified_light(r, g);
                assert_ne!(l, Light::Yellow, "certified r={r} g={g} must not be yellow");
                assert_eq!(l, if g < r { Light::Green } else { Light::Red });
            }
        }
    }

    #[test]
    fn net_saved_signs_match_door() {
        // door pays: many hits of expensive recompute beat the gate.
        assert!(net_saved(100, 100, 1000, 1, 0) > 0);
        // door loses: cheap recompute, all gate cost (the FOIL 0.84× / frf trap).
        assert!(net_saved(100, 0, 0, 1, 0) < 0);
    }
}
